public class HoverboardGrindController : MonoBehaviour
{
    [Header("Grind UI")]
    public Slider grindBalanceSlider; // The slider component that shows grinding balance

    [Header("Grind Settings")]
    [Tooltip("Speed of movement along the grind surface")]
    public float grindSpeed = 10f;
    [Tooltip("Position reference for grindable object")]
    public Transform grindPosition;
    [Tooltip("Vector representing the direction of grinding")]
    public Vector3 localGrindDirection;

    [Header("Grind Detection")]
    [Tooltip("Radius to search for grindable surfaces")]
    public float detectionRadius = 5f;
    [Tooltip("Layer mask marking grindable surfaces")]
    public LayerMask grindableLayer;
    [Tooltip("Key to initiate the grinding")]
    public KeyCode grindKey = KeyCode.G;

    private Rigidbody rb;
    private bool isGrinding;
    private GrindableSurface currentGrindSurface;
    private float balanceChangeTimer = 0f;
    private int grindDirection = 1; // Used to simulate balance challenge
    public float balanceTimeDuration = 2f;
    public float balanceDifficulty = 20f;

    void Awake()
    {
        rb = GetComponent<Rigidbody>();
    }

    void Update()
    {
        if (isGrinding)
        {
            GrindBalanceManager();
            GrindMovement();
        }
    }

    public GrindableSurface FindClosestGrindableSurface()
    {
        Collider[] hits = Physics.OverlapSphere(transform.position, detectionRadius, grindableLayer);
        GrindableSurface closestSurface = null;
        float closestDistanceSqr = Mathf.Infinity;
        Vector3 currentPosition = transform.position;

        foreach (Collider hit in hits)
        {
            GrindableSurface surface = hit.GetComponent<GrindableSurface>();
            if (surface != null)
            {
                Vector3 directionToSurface = hit.transform.position - currentPosition;
                float dSqrToSurface = directionToSurface.sqrMagnitude;
                if (dSqrToSurface < closestDistanceSqr)
                {
                    closestDistanceSqr = dSqrToSurface;
                    closestSurface = surface;
                }
            }
        }

        return closestSurface;
    }

    public void StartGrinding(Transform grindSurface, Vector3 direction)
    {
        if (!isGrinding)
        {
            isGrinding = true;

            grindPosition = grindSurface;
            localGrindDirection = direction.normalized;

            // Set the hoverboard's position and rotation according to the grindable surface's
            transform.position = grindPosition.position;
            transform.forward = localGrindDirection;

            grindBalanceSlider.gameObject.SetActive(true);
            grindBalanceSlider.value = 0f; // Reset the grind balance to neutral
        }
    }

    public void EndGrinding()
    {
        if (isGrinding)
        {
            isGrinding = false;
            grindBalanceSlider.gameObject.SetActive(false);
            // Additional logic upon ending the grind can be implemented here
        }
    }

    private void GrindBalanceManager()
    {
        // Simulates balancing challenge while grinding
        grindBalanceSlider.value += grindDirection * Time.deltaTime * balanceDifficulty;
        balanceChangeTimer += Time.deltaTime;
        if (balanceChangeTimer >= balanceTimeDuration)
        {
            grindDirection *= -1; // Flip the balance direction
            balanceChangeTimer = 0f;
        }

        // Clamp the slider value to prevent it from going out of bounds
        grindBalanceSlider.value = Mathf.Clamp(grindBalanceSlider.value, -1f, 1f);
    }

    private void GrindMovement()
    {
        if (currentGrindSurface != null)
        {
            // Calculate the next position based on the direction and speed of the grindable surface
            Vector3 grindTargetPosition = transform.position + localGrindDirection * currentGrindSurface.GetSpeed() * Time.deltaTime;
            transform.position = Vector3.MoveTowards(transform.position, grindTargetPosition, currentGrindSurface.GetSpeed() * Time.deltaTime);
        }
    }

    private void OnTriggerEnter(Collider other)
    {
        if (other.CompareTag("Grindable"))
        {
            GrindableSurface surface = other.GetComponent<GrindableSurface>();
            if (surface != null)
            {
                StartGrinding(other.transform, surface.GetDirection());
            }
        }
    }

    private void OnTriggerExit(Collider other)
    {
        if (other.CompareTag("Grindable"))
        {
            EndGrinding();
        }
    }
}
